#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAXN 100005
#define MAXE 1000005

int N, E;
int u[MAXE], v[MAXE], x[MAXE];
int cost[MAXN][MAXN];

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &E);
        for (int i = 0; i < E; i++) {
            scanf("%d %d %d", &u[i], &v[i], &x[i]);
            cost[u[i]][v[i] - N] = x[i];
        }
        // Assign costs to missing edges
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                if (cost[i][j] == 0) {
                    // Use a system of linear equations to find the cost
                    int sum = 0;
                    for (int k = 1; k <= N; k++) {
                        if (k != i) {
                            sum += cost[k][j];
                        }
                    }
                    cost[i][j] = sum / (N - 1);
                }
            }
        }
        // Calculate the sum of squares of all edge costs
        long long sum = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                sum += (long long)cost[i][j] * cost[i][j];
            }
        }
        printf("%lld\n", sum % MOD);
    }
    return 0;
}

